13	      })
14	      .catch(() => {
15	        if (mounted) setReduced(false);
16	      });
17	
18	    const sub = AccessibilityInfo.addEventListener('reduceMotionChanged', setReduced);
19	    return () => {
20	      mounted = false;
21	      sub.remove();
22	    };
23	  }, []);
24	
25	  return reduced;
26	}
